const event = $json.body && $json.body.events && $json.body.events.length > 0 ?   
  $json.body.events[0] :  
  null;

console.log("=== Parse Postback Data ===");

if (!event) {
  console.log("❌ No event found");
  return [{
    json: {
      userId: "unknown",
      replyToken: "unknown",
      messageType: 'unknown',
      mode: 'welcome',
      action: null,
      hasError: true
    }
  }];
}

const userId = event.source?.userId || "unknown";
const replyToken = event.replyToken;

console.log("✓ Parsed Event:", { userId, replyToken, eventType: event.type });

// ===== 6個菜系對照表 (完整保留) =====
const cuisineMap = {
  'chinese': '中式料理',
  'taiwanese': '中式料理',
  'bbq': '中式料理',
  'seafood': '中式料理',
  'japanese': '日式料理',
  'hotpot': '火鍋',
  'healthy': '健康餐',
  'vegetarian': '健康餐',
  'cafe': '咖啡廳',
  'international': '異國料理',
  'italian': '異國料理',
  'korean': '異國料理'
};

const cuisineMapReverse = {
  '中式料理': 'chinese',
  '日式料理': 'japanese',
  '火鍋': 'hotpot',
  '健康餐': 'healthy',
  '咖啡廳': 'cafe',
  '異國料理': 'international'
};

const chineseCuisines = Object.values(cuisineMap);

// ===== Follow 事件 (完整保留) =====
if (event.type === 'follow') {
  console.log("Event type: follow");
  return [{
    json: {
      userId: userId,
      replyToken: replyToken,
      messageType: 'follow',
      action: 'follow',
      mode: 'welcome',
      originalText: 'follow'
    }
  }];
}

// ===== Text Message (完整保留，僅調整老用戶 Action) =====
if (event.message && event.message.type === 'text') {
  const text = (event.message.text || "").trim();
  const textLower = text.toLowerCase();

  console.log("Event type: text message, Text:", text);

  if (text === "我是新用戶!!") {
    console.log("✓ Action: first_time");
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "first_time",
        mode: "setup_profile",
        originalText: text
      }
    }];
  }

  if (text === "我是老鳥了!!") {
    console.log("✓ Action: existing_user");
    // ✅ 這裡修改為觸發確認位置模式，其餘欄位保留
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "existing_user",
        mode: "confirm_location", 
        originalText: text
      }
    }];
  }

  if (textLower.includes("trip") && textLower.includes("規劃")) {
    console.log("✓ Mode: trip_planning");
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "trip_planning",
        mode: "trip_planning",
        originalText: text
      }
    }];
  }

  if (textLower.includes("instant") && textLower.includes("搜尋")) {
    console.log("✓ Mode: instant_search");
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "instant_search",
        mode: "instant_search",
        originalText: text
      }
    }];
  }

  if (textLower.includes("query") || textLower.includes("history") || textLower.includes("歷史")) {
    console.log("✓ Mode: query_history");
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "query_history",
        mode: "query_history",
        originalText: text
      }
    }];
  }

  if (chineseCuisines.includes(text)) {
    const cuisineEnglish = cuisineMapReverse[text] || '';
    console.log("✓ Cuisine selected (text input):", text);
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageText: text,
        messageType: 'text',
        action: "select_cuisine",
        mode: "select_cuisine",
        cuisine_type: text,
        cuisine_type_english: cuisineEnglish,
        originalText: text
      }
    }];
  }

  // 普通文字（可能是正在更新地址文字）
  console.log("Mode: unknown (normal text message)");
  return [{
    json: {
      userId: userId,
      replyToken: replyToken,
      messageText: text,
      messageType: 'text',
      action: "text_input", // ✅ 增加識別方便後續判斷更新地址
      mode: 'unknown',
      originalText: text
    }
  }];
}

// ===== Postback (完整保留並插入新邏輯) =====
if (event.postback && event.postback.data) {
  const postbackData = event.postback.data;
  console.log("Event type: postback", postbackData);

  const params = {};
  const pairs = postbackData.split('&');
  for (let i = 0; i < pairs.length; i++) {
    const pair = pairs[i].split('=');
    if (pair.length === 2) {
      params[decodeURIComponent(pair[0])] = decodeURIComponent(pair[1]);
    }
  }

  const action = params.action || 'unknown';
  console.log("✓ Postback Parsed:", { action, params });

  // --- 🆕 新增：老用戶位置確認分支 (不影響後續) ---
  if (action === 'use_stored_location') {
    return [{ json: { userId, replyToken, messageType: 'postback', action, mode: 'existing_mode_selection', originalText: postbackData } }];
  }
  if (action === 'update_location_trigger') {
    return [{ json: { userId, replyToken, messageType: 'postback', action, mode: 'asking_new_address', originalText: postbackData } }];
  }
  // --- 🆕 新增：分頁導覽分支 ---
  if (action === 'show_cuisine_page1' || action === 'show_cuisine_page2') {
    return [{ json: { userId, replyToken, messageType: 'postback', action, mode: 'select_cuisine_navigation', originalText: postbackData } }];
  }

  // --- Setup 初始化 (完整保留) ---
  if (action === 'setup_profile') {
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: 'setup_profile',
        mode: 'setup_profile',
        setup_step: 0,
        originalText: postbackData
      }
    }];
  }

  // --- Setup 步驟按鈕 (完整保留) ---
  if (['setup_gender', 'setup_dietary', 'setup_allergies', 'setup_dislikes'].includes(action)) {
    const setupValue = params.value || '';
    const currentStep = parseInt(params.step) || 0;
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'setup_profile',
        setup_step: currentStep + 1,
        setup_value: setupValue,
        originalText: postbackData
      }
    }];
  }

  // --- Instant Search (完整保留) ---
  if (action === 'instant_search' || action === 'instant_search_start') {
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'instant_search',
        search_type: params.search_type || 'quick',
        originalText: postbackData
      }
    }];
  }

  // --- Trip Planning (完整保留) ---
  if (action === 'trip_planning' || action === 'trip_planning_start') {
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'trip_planning',
        originalText: postbackData
      }
    }];
  }

  // --- Query History (完整保留) ---
  if (action === 'query_history') {
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'query_history',
        originalText: postbackData
      }
    }];
  }

  // --- 菜系選擇（英文代碼） (完整保留所有參數) ---
  if (action === 'cuisine') {
    const cuisineEnglish = params.cuisine || '';
    const cuisineChinese = cuisineMap[cuisineEnglish] || cuisineEnglish;
    console.log("✓ Cuisine (action=cuisine):", { cuisineEnglish, cuisineChinese });
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'select_cuisine',
        cuisine_type: cuisineChinese,
        cuisine_type_english: cuisineEnglish,
        search_type: params.search_type || 'quick',
        sort_by: params.sort_by || '',
        originalText: postbackData
      }
    }];
  }

  // --- 菜系選擇（中文名稱） (完整保留) ---
  if (action === 'select_cuisine') {
    const cuisineChinese = params.cuisine || '';
    const cuisineEnglish = cuisineMapReverse[cuisineChinese] || '';
    console.log("✓ Cuisine (action=select_cuisine):", { cuisineChinese, cuisineEnglish });
    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: action,
        mode: 'select_cuisine',
        cuisine_type: cuisineChinese,
        cuisine_type_english: cuisineEnglish,
        originalText: postbackData
      }
    }];
  }

 // --- 👍 推薦反饋 (優化版：支援 UUID 精準追蹤) ---
  if (action === 'like' || action === 'like_or_dislike') {
  console.log("✓ Feedback received:", { action, res_id: params.res_id });

    const cuisineEnglish = params.cuisine_type || '';
    const cuisineChinese = cuisineMap[cuisineEnglish] || cuisineEnglish;

    return [{
      json: {
        userId: userId,
        replyToken: replyToken,
        messageType: 'postback',
        action: 'like',               // 統一輸出為 like 方便後續 Switch
        mode: 'update_feedback',      // 標記模式
        recommendation_id: params.rec_id || '',      // 主表 ID (新)
        restaurant_detail_id: params.res_id || params.restaurant_id || '', // 相容新舊 ID
        restaurant_name: params.name || params.restaurant_name || '這家餐廳',
        cuisine_type: cuisineChinese,
        isFeedback: true,
        originalText: postbackData
    }
  }];
 }

 // --- 🆕 新增：查看歷史明細 (穿透式查詢) ---
 if (action === 'view_history_detail') {
  console.log("✓ User requested history detail, rec_id:", params.rec_id);
  return [{
    json: {
      userId: userId,
      replyToken: replyToken,
      messageType: 'postback',
      action: 'view_history_detail', // 給第一個 Switch 判斷用
      mode: 'view_history_detail',
      recommendation_id: params.rec_id || '', // 關鍵：這是要傳給 Supabase 的外鍵 ID
      originalText: postbackData
    }
  }];
 }
}

// ===== 默認回應 (完整保留) =====
return [{
  json: {
    userId: userId,
    replyToken: replyToken,
    messageType: 'unknown',
    mode: 'welcome',
    action: null,
    isFeedback: false
  }
}];

// 取代原本的 Format Restaurants (Top 5) 程式碼
const results = $json.results || [];

// 只取前 6 名，並將每一家餐廳轉化為一個獨立的 Item 輸出
return results.slice(0, 6).map((r, idx) => ({
    rank: idx + 1,
    name: r.name,
    place_id: r.place_id,
    rating: r.rating || 0,
    address: r.vicinity,
    // 先暫存 photo_reference，細節節點可以再決定是否處理圖片
    photo_reference: r.photos?.[0]?.photo_reference || null
}));

