// 1. 取得搜尋結果
const results = $json.results || [];

// 2. 從前面的節點抓取全域資訊 (使用 .first() 確保穩定性)
const userId = $("Supabase: Get User For Cuisine Details Search").first().json.line_user_id;
const cuisineType = $('Parse Postback Data').first().json.cuisine_type || '未指定菜系';

// 3. 格式化並「拆分」成獨立項目 (Items)
