parameters.jsCode:
const input = $json;

console.log("=== Supabase Fetch Response Parser ===");
console.log("Raw input structure:", {
  hasBody: !!input.body,
  bodyType: Array.isArray(input.body) ? "array" : typeof input.body,
  hasResponse: !!input.response
});

// Supabase 把返回數據放在 response. body 中
let data = null;

// 方式 1: response.body 是陣列（最常見）
if (input. response && input.response.body && Array.isArray(input.response.body)) {
  data = input.response.body[0];
  console.log("✓ Found data in response.body array");
}
// 方式 2: 直接 input.body 是陣列
else if (Array.isArray(input.body)) {
  data = input.body[0];
  console.log("✓ Found data in input.body array");
}
// 方式 3: body 是對象
else if (input.body && input.body.id) {
  data = input.body;
  console.log("✓ Found data in input. body object");
}
// 方式 4: 直接是對象（容錯方案）
else if (input.id || input.line_user_id) {
  data = input;
  console.log("✓ Found data at root level");
}

// 檢查是否成功提取數據
if (! data) {
  console.log("❌ No data found");
  console.log("Full input:", JSON.stringify(input, null, 2));
  return [{
    json: {
      error: true,
      message: "Could not extract data from response",
      debug: {
        has_body: !!input.body,
        has_response: !!input.response,
        input_keys: Object.keys(input)
      }
    }
  }];
}

// 成功提取，返回結構化的數據
console.log("✓ Data extracted successfully");
console.log("Setup step:", data.setup_step);

return [{
  json: {
    success: true,
    setup_id: data.id,
    line_user_id: data.line_user_id,
    setup_step: data.setup_step || 0,
    name: data.name || null,
    age: data.age || null,
    gender: data.gender || null,
    height: data.height || null,
    weight: data.weight || null,
    allergies: data. allergies || null,
    dislikes: data.dislikes || null,
    dietary_goals: data.dietary_goals || null,
    address: data.address || null,
    reply_token: data.reply_token,
    created_at: data. created_at,
    updated_at: data.updated_at
  }
}];

