const response = $json; 
// 關鍵修正：強制引用最初 Webhook 解析出來的資料，確保 Token 與輸入文字永遠是最新的
const lineEvent = $('Parse Postback Data').item.json;

console.log("=== Parse Setup Progress ===");

// 1. 提取 Supabase 紀錄 (處理陣列或單個物件格式)
const record = Array.isArray(response) ? response[0] : (response && response.id ? response : null);

// 2. 判斷是否有真正的紀錄 (檢查是否存在 ID)
const hasRecord = !!(record && record.id);

if (hasRecord) {
    console.log("✓ Record found. Step:", record.setup_step);
    return [{
        json: {
            success: true,
            has_record: true,
            setup_step: record.setup_step,
            line_user_id: record.line_user_id,
            setup_data: {
                // 這裡會將你資料庫中已有的欄位全部對應過去
                name: record.name,
                age: record.age,
                gender: record.gender,
                height: record.height,
                weight: record.weight,
                allergies: record.allergies,
                dislikes: record.dislikes,
                dietary_goals: record.dietary_goals,
                address: record.address
            },
            // 核心修正：這兩項必須引用 LINE 當下的事件資料
            reply_token: lineEvent.replyToken,
            messageText: lineEvent.messageText
        }
    }];
}

// 3. ✗ 找不到紀錄的分支：回傳您要求的 -1
console.log("No record found - returning -1");
return [{
    json: {
        success: true,
        has_record: false,
        setup_step: -1,
        line_user_id: lineEvent.userId,
        setup_data: {
            name: null, age: null, gender: null, height: null, weight: null,
            allergies: null, dislikes: null, dietary_goals: null, address: null
        },
        reply_token: lineEvent.replyToken,
        messageText: lineEvent.messageText,
