parameters.jsCode:
const messageText = $input.first().json.messageText;

console.log("=== Process Allergies Input ===");
console.log("Raw input:", JSON.stringify(messageText));

// 驗證過敏原不為空
if (! messageText || messageText.trim() === "") {
  console.log("❌ 過敏原為空");
  return [{
    json: {
      success: false,
      error: "過敏原不能為空，請輸入你的過敏原 (例如: 花生,牛奶 或 無)："
    }
  }];
}

const allergies = messageText.trim();

// ===== 常見過敏原列表（只列常見的） =====
const commonAllergens = [
  "花生", "堅果", "牛奶", "蝦", "蟹", "貝類", "海鮮",
  "雞蛋", "蛋", "小麥", "芝麻", "魚", "大豆", "黃豆",
  "無"  // 表示沒有過敏原
];

// 檢查是否包含常見過敏原
let hasCommonAllergen = false;

for (let allergen of commonAllergens) {
  if (allergies.includes(allergen)) {
    hasCommonAllergen = true;
    console. log("✓ 檢測到常見過敏原:", allergen);
    break;
  }
}

// 如果沒有檢測到常見過敏原，拒絕
if (!hasCommonAllergen) {
  console.log("❌ 沒有檢測到常見過敏原");
  return [{
    json: {
      success: false,
      error: "⚠️ 你輸入的「${allergies}」不在常見過敏原列表中。常見過敏原：花生、堅果、牛奶、海鮮、雞蛋、小麥、芝麻、大豆等。如果有其他過敏原，請重新表述。或輸入「無」:"
    }
  }];
}

// ✓ 過敏原有效
console.log("✓ 過敏原有效：", allergies);

return [{
  json: {
    success: true,
    allergies: allergies
  }
}];

