parameters.jsCode:
// 1. 獲取所有進入此節點的項目 (目前應該是 5 個獨立項目)
const allItems = $input.all();

// 2. 針對每一筆資料進行清理與評論提取
const cleanedRestaurants = allItems.map((item, index) => {
    const res = item.json.result || {};

    // 提取評論關鍵字 (前 3 則)
    const reviewSnippets = res.reviews 
        ? res.reviews.slice(0, 3).map(r => r.text).join(" | ") 
        : "無評論";

    return {
        // 修正 1：將原始排名重新加回去 (index 從 0 開始，所以要 +1)
        rank: index + 1, 

        name: res.name || "未知餐廳",

        // 修正 2：確保評分被正確抓取，如果 Details 沒回傳則抓搜尋結果的評分
        rating: res.rating || item.json.rating || 0, 

        google_types: res.types ? res.types.join(', ') : '',
        summary: res.editorial_summary ? res.editorial_summary.overview : '無官方描述',
        is_veggie: res.serves_vegetarian_food ? '是' : '否',

        // 解惑：Price Level 2 代表 Google 定義的「中價位 ($$)」，通常是 250-500 元
        price_level: res.price_level || '2', 

        user_keywords: reviewSnippets, 
        address: res.formatted_address || item.json.address,

        // 修正 3：確保 Place ID 有傳給 AI，後續按鈕才不會失效
        place_id: item.json.place_id || res.place_id 
    };
});

// 3. 將 5 筆資料打包在一個 "restaurants" 陣列中回傳給 AI
return {
    restaurants: cleanedRestaurants
};

// 格式化混合菜系 Top6 為卡片格式

const restaurants = $json.mixed_top6 || [];

console.log("=== Format Mixed Top6 ===");
console.log("Restaurants to format:", restaurants.length);

return {
  userId: $json. userId,
  replyToken:  $json.replyToken,
  restaurants: restaurants.slice(0, 6).map((r, idx) => ({
    rank: idx + 1,
    name: r. name,
    rating: r. rating || 0,
    address: r.address,
    place_id: r.place_id,
    cuisine_type: r.cuisine_type,
    reason: r.reason || ''
  }))
};

// 1. 獲取此節點接收到的所有項目
const allItems = $input.all();

// 2. 整理數據
const cleanedList = allItems.map(item => {
  const details = item.json.result || {};

  // 提取評論
  const reviewSnippets = details.reviews 
    ? details.reviews.slice(0, 3).map(r => r.text).join(' | ') 
    : "暫無評論";

  // 處理價格等級 (0-4 轉為 $ 符號)
  const priceLevel = details.price_level !== undefined ? "$".repeat(details.price_level) : "未提供";

  // 處理照片 (構造完整的 Google 圖片 URL)
  const photoRef = details.photos?.[0]?.photo_reference;
  const apiKey = "AIzaSyDbceqX4fTLZAPP22JkxInA9qMs1j-oQ4I"; // 建議這裡填入您的 Key
  const photoUrl = photoRef 
    ? `https://maps.googleapis.com/maps/api/place/photo?maxwidth=400&photo_reference=${photoRef}&key=${apiKey}`
    : null;

  return {
    rank: item.pairedItem.item + 1,
    name: details.name,
    rating: details.rating || 0,
    address: details.formatted_address,
    summary: details.editorial_summary?.overview || "未提供簡介",
    user_reviews: reviewSnippets,
    is_vegetarian_friendly: details.serves_vegetarian_food ? "是" : "否",
    place_id: details.place_id,
    price_rating: details.price_level,
    photo_url: photoUrl
  };
});

// 3. 返回數據給 AI 與後續儲存
return {
  userId: $('Supabase: Get User For Cuisine Details Search').first().json.line_user_id,
  cuisine_type: $('Parse Postback Data').first().json.cuisine_type,
  cuisine_restaurants: cleanedList
};

// === 優化版：提取並合併資料數據 ===

const input = $json;
const originalCleanedData = $('清理 Place Details 數據1').first().json.cuisine_restaurants; // 抓取原始數據

let nutritionData = null;

// 1. 解析 AI 輸出 (維持您原本強大的相容性邏輯)
if (Array.isArray(input)) {
    nutritionData = input[0]?.output || input[0];
} else if (input.output) {
    nutritionData = input.output;
} else if (input.response?.generations?.[0]?.[0]?.text) {
    try {
        const text = input.response.generations[0][0].text;
        nutritionData = JSON.parse(text.replace(/```json|```/g, ""));
    } catch (e) { console.log("LLM parse failed"); }
} else {
    nutritionData = input;
}

// 2. 數據驗證
if (!nutritionData || !nutritionData.individual_recommendations) {
    return [{ json: { success: false, error: "AI 輸出格式錯誤" } }];
}

// 3. 【優化點】數據再合併 (Merging)
// 將 AI 的分析內容補回原始帶有照片與價格的數據中
const enrichedRecommendations = nutritionData.individual_recommendations.map(aiItem => {
    // 透過 place_id 找回當初從 Google 抓到的原始資料
    const original = originalCleanedData.find(o => o.place_id === aiItem.place_id);

    return {
        ...aiItem,
        // 強制校正：確保照片和價格是從原始資料來的，不被 AI 影響
        photo_url: original?.photo_url || aiItem.photo_url,
        price_rating: original?.price_rating || aiItem.price_rating,
        rating: original?.rating || aiItem.rating,
        address: original?.address || aiItem.address
    };
});

// 4. 返回整齊數據
return [{
    json: {
        success: true,
        calories_target: nutritionData.calories_target,
        comparison_summary: nutritionData.comparison_summary,
        // 這是合併後的完美清單，包含營養分析 + 正確的照片/價格
        recommendations: enrichedRecommendations 
    }
}];

