parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "calories_target": {
      "type": "string",
      "description": "建議此餐攝取的熱量目標數值，格式如：550 kcal。"
    },
    "comparison_summary": {
      "type": "string",
      "description": "這 5 家餐廳的橫向對比精華。必須明確指出哪一家最符合用戶目前的健康目標，嚴禁籠統描述。"
    },
    "individual_recommendations": {
      "type": "array",
      "description": "針對每家餐廳生成的個性化建議清單，數量必須精確為 5 筆。",
      "items": {
        "type": "object",
        "properties": {
          "rank": { "type": "number", "description": "推薦排名 (1-5)。" },
          "name": { "type": "string", "description": "餐廳官方名稱。" },
          "rating": { "type": "number", "description": "Google 評分。" },
          "address": { "type": "string", "description": "餐廳詳細地址。" },
          "place_id": { "type": "string", "description": "從原始資料帶入的 Google Place ID。" },
          "price_rating": { "type": "string", "description": "餐廳價格等級描述。" },
          "photo_url": { "type": "string", "description": "餐廳照片原始網址。" },
          "cp_analysis": { 
            "type": "string", 
            "description": "該店在本次推薦中的獨特定位與優點。嚴禁與清單中其他餐廳重複，需強調與眾不同之處。" 
          },
          "specific_menu": { 
            "type": "string", 
            "description": "根據評論挖掘出的 1-2 道建議菜名，需說明推薦理由。" 
          },
          "avoid_items": { 
            "type": "string", 
            "description": "針對用戶目標與禁忌，建議在該店避開的具體高熱量或不健康品項。" 
          },
          "nutrition_tips": { 
            "type": "string", 
            "description": "根據該餐廳『特定菜系』提供的專業點餐撇步（例如：日式減飯、火鍋換原型食物）。嚴禁對 5 家店給出相同建議。" 
          }
        },
        "required": ["rank", "name", "cp_analysis", "specific_menu", "avoid_items", "nutrition_tips", "place_id"]
      }
    }
  },
  "required": [
    "calories_target",
    "comparison_summary",
    "individual_recommendations"
  ]
}
